src/DQM.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.17;
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
interface IDQToken {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
    function burn(uint256 amount) external;
    function totalSupply() external view returns (uint256);
}
interface IDQCard {
    function balanceOf(address owner) external view returns (uint256);
    function mintByOwner(address to, uint256 _type) external;
    function getCardPrice(uint256 _type) external pure returns (uint256);
}
interface IPancakeRouter02 {
    function getAmountsOut(uint amountIn, address[] calldata path) external view returns (uint[] memory amounts);
    function swapExactTokensForTokensSupportingFeeOnTransferTokens(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) external;
    function addLiquidity(address tokenA, address tokenB, uint amountADesired, uint amountBDesired, uint amountAMin, uint amountBMin, address to, uint deadline) external returns (uint amountA, uint amountB, uint liquidity);
}
interface IDQMiningStake {
    function registerUser(address _u, address _r) external;
    function importUser(address _u, address _r, uint256 _total, uint256 _team, uint8 _level, uint256 _energy) external;
    function lpPair() external view returns (address);
    function setEnergyMul(uint256 _m) external;
    function addEnergy(address _u, uint256 _a) external;
    function subEnergy(address _u, uint256 _a) external;
    function addTeamInvest(address _u, uint256 _a) external;
    function updateTeam(address _u, uint256 _a) external;
    function addDirectSales(address _u, uint256 _a) external;
    function addChild(address _p, address _c) external;
    function addPendingSOL(address _u, uint256 _a) external;
    function subPendingSOL(address _u, uint256 _a) external;
    function updateValidAddress(address _u) external;
    function distReward(address _u, uint256 _dyn) external;
    function addLP(address _u, uint256 _a, uint256 _t) external;
    function getDirectSales(address _u) external view returns (uint256);
    function distLP(uint256 f) external;
    function claimLP(address u) external;
    function claimNft(address _u) external;
    function claimD(address _u) external;
    function claimFee(address _u) external;
    function claimPdq(address _u) external;
    function registerDLevel(address _user, uint8 _level) external;
    function claimPbnb(address _u) external;
    function withdraw(address _u, uint256 _a) external;
    function withdrawLP(address _u) external;
    function getUserLPRemovalFee(address _u) external view returns (uint256);
    function clearUserLPRemovalFee(address _u) external;
    function distDQFee(uint256 _amount) external;
    function distNFT(uint256 _fee) external payable;
    function stake(address _u, uint256 _a, uint _i) external;
    function unstake(address _u, uint _i) external;
    function clmS(address _u, uint _i) external;
    function mine() external;
    function getTeamInvest(address _u) external view returns (uint256);
    function getEnergy(address _u) external view returns (uint256);
    function getPendingSOL(address _u) external view returns (uint256);
    function subPendingBurn(address _u, uint256 _amount) external;
}
contract DQMiningV3 is ReentrancyGuard {
    using EnumerableSet for EnumerableSet.AddressSet;
    using SafeERC20 for IERC20;
    address public constant OWNER = 0x274aCc6397349F21179ed6258A54B2a11B28faF5;
    address public constant SOL = 0x570A5D26f7765Ecb712C0924E4De545B89fD43dF;
    address public constant ROUTER = 0x10ED43C718714eb63d5aA57B78B54704E256024E;
    address public FOUNDATION = 0xA0f045cde45ca1aeE2033356170B46A1fF3b7202;
    address public constant OP = 0x4bE56C5390869A3236F8545462896eB1E423D0d5;
    address public constant STAKE_OP = 0x7cc3260b1E4e1d830A6a92A3b2F77257fbab169F;
    address public constant INS = 0x2db993B862969040Cd971Df8Fd2a2C80EC285203;
    address public constant BUY_FEE = 0x1850933c0d64db3A56476F5Bdc4191BCFd242e30;
    address public constant DAO = 0x27b84FC9eb5C3a19585093aD6D11292cbbaB5852;
    IDQToken public dqToken;
    IDQCard public dqCard;
    address public stakeContract;
    uint256 public constant INVEST_MIN = 1 ether;
    uint256 public constant DAILY_LIMIT = 1 ether;
    uint256 public currentPhase = 1;
    uint256 public constant PHASE_STEP = 5 ether;
    uint256[4] public nodePrices = [0, 500 ether, 1500 ether, 5000 ether];
    uint256 public constant DIRECT_RATE = 30;
    uint256 public constant SEE_RATE = 15;
    uint256 public constant DAO_RATE = 10;
    uint256 public constant INS_RATE = 7;
    uint256 public constant OP_RATE = 8;
    uint256 public constant ENERGY_MUL = 3;
    uint256 public constant WITHDRAW_FEE = 10;
    uint256 public constant FEE_NODE_RATE = 40;
    uint256 public constant FEE_PARTNER_RATE = 30;
    uint256 public constant FEE_FOUNDATION_RATE = 30;
    uint256 public constant CLAIM_BNB_FEE = 0.00005 ether;
    uint256 public constant MGR_RATE = 30;
    uint256 public SLIPPAGE = 995;  
    uint256 public constant SELL_FEE = 6;         
    uint256 public constant BURN_STOP_THRESHOLD = 99;
    uint256 public constant INITIAL_SUPPLY = 100000000000 * 10**18;
    struct User {
        address referrer;
        uint256 directCount;
        uint8 level;
        uint256 totalInvest;
        EnumerableSet.AddressSet children;
    }
    mapping(address => User) internal users;
    address[] public allUsers;
    mapping(address => bool) public isBlacklisted;
    mapping(address => bool) public authorized;  
    mapping(address => uint256) public dailyDeposit;
    mapping(address => bool) public depositWhiteList;
    uint256 public nftPendingSOL;
    uint256 public partnerPendingSOL;
    uint256 public startTime;
    event Register(address indexed u, address indexed r);
    event Deposit(address indexed u, uint256 a);
    event SwapAndAddLP(address indexed u, uint256 s, uint256 d, uint256 l);
    event SellDQ(address indexed u, uint256 d, uint256 s, uint256 b, uint256 f);
    event ClaimReward(address indexed user, uint256 amount, uint256 fee);
    event ReinvestSOL(address indexed user, uint256 amount, uint256 energyAdded);
    event WithdrawBNB(address indexed to, uint256 amount);
    modifier onlyOwner() { require(msg.sender == OWNER, "!owner"); _; }
    modifier onlyReg() { require(users[msg.sender].referrer != address(0) || msg.sender == OWNER, "!reg"); _; }
    constructor() { startTime = block.timestamp; users[OWNER].referrer = address(0); allUsers.push(OWNER); authorized[OWNER] = true; }
    function grantAuth(address _auth) external onlyOwner { authorized[_auth] = true; }
    function revokeAuth(address _auth) external onlyOwner { authorized[_auth] = false; }
    function setDQToken(address _addr) external onlyOwner { require(_addr != address(0), "!addr"); dqToken = IDQToken(_addr); }
    function setDQCard(address _addr) external onlyOwner { require(_addr != address(0), "!addr"); dqCard = IDQCard(_addr); }
    function setStakeContract(address _a) external onlyOwner { require(_a != address(0), "!addr"); stakeContract = _a; IDQMiningStake(_a).setEnergyMul(ENERGY_MUL); }
    function setFoundation(address _addr) external onlyOwner { require(_addr != address(0), "!addr"); FOUNDATION = _addr; }
    function setSlippage(uint256 _s) external onlyOwner { require(_s <= 1000, "!"); SLIPPAGE = _s; }  
    function setDepositWhiteList(address _u, bool _s) external onlyOwner { depositWhiteList[_u] = _s; }
    function addToBlacklist(address _u) external onlyOwner { isBlacklisted[_u] = true; }
    function removeFromBlacklist(address _u) external onlyOwner { isBlacklisted[_u] = false; }
    function register(address _r) external {
        require(_r != msg.sender && users[msg.sender].referrer == address(0), "!inv");
        if (_r != address(0)) {
            require(users[_r].referrer != address(0) || _r == OWNER, "!rref");
            users[_r].directCount++;
            users[_r].children.add(msg.sender);
        }
        users[msg.sender].referrer = _r;
        allUsers.push(msg.sender);
        if (stakeContract != address(0)) IDQMiningStake(stakeContract).registerUser(msg.sender, _r);
        emit Register(msg.sender, _r);
    }
    function importUser(address _u, address _r) external onlyOwner {
        require(users[_u].referrer == address(0), "already");
        users[_u].referrer = _r;
        allUsers.push(_u);
        if (_r != address(0) && users[_r].referrer != address(0)) {
            users[_r].directCount++;
            users[_r].children.add(_u);
        }
        if (stakeContract != address(0)) {
            User storage u = users[_u];
            IDQMiningStake(stakeContract).importUser(_u, _r, u.totalInvest, 0, u.level, 0);
        }
        emit Register(_u, _r);
    }
    function setReferrer(address _u, address _r) external onlyOwner {
        require(users[_u].referrer != address(0), "!reg");
        require(users[_u].children.length() == 0, "has children");
        require(_r != _u, "self");
        require(users[_r].referrer != address(0) || _r == OWNER, "!rref");
        address oldRef = users[_u].referrer;
        if (oldRef != address(0)) {
            users[oldRef].directCount--;
            users[oldRef].children.remove(_u);
        }
        users[_u].referrer = _r;
        users[_r].directCount++;
        users[_r].children.add(_u);
        emit Register(_u, _r);
    }
    function setUserLevel(address _u, uint8 _lvl) external onlyOwner { require(_lvl >= 1 && _lvl <= 6, "!level"); users[_u].level = _lvl; }
    function setUserDLevel(address _u, uint8 _lvl) external onlyOwner { require(_lvl <= 8, "!Dlevel"); if (stakeContract != address(0)) IDQMiningStake(stakeContract).registerDLevel(_u, _lvl); }
    function importUsers(address[] calldata _u, address[] calldata _r) external onlyOwner {
        require(_u.length == _r.length, "!len");
        for (uint i = 0; i < _u.length; i++) {
            if (users[_u[i]].referrer != address(0)) continue;
            users[_u[i]].referrer = _r[i];
            allUsers.push(_u[i]);
            if (_r[i] != address(0) && users[_r[i]].referrer != address(0)) {
                users[_r[i]].directCount++;
                users[_r[i]].children.add(_u[i]);
            }
            if (stakeContract != address(0)) {
                IDQMiningStake(stakeContract).registerUser(_u[i], _r[i]);
            }
            emit Register(_u[i], _r[i]);
        }
    }
    function setNodesLevel(address[] calldata _u, uint8[] calldata _lvl) external onlyOwner {
        require(_u.length == _lvl.length, "!len");
        for (uint i = 0; i < _u.length; i++) {
            require(_lvl[i] >= 1 && _lvl[i] <= 6, "!level");
            users[_u[i]].level = _lvl[i];
        }
    }
    function setNodesDLevel(address[] calldata _u, uint8[] calldata _lvl) external onlyOwner {
        require(_u.length == _lvl.length, "!len");
        for (uint i = 0; i < _u.length; i++) {
            require(_lvl[i] <= 8, "!Dlevel");
            if (stakeContract != address(0)) {
                IDQMiningStake(stakeContract).registerDLevel(_u[i], _lvl[i]);
            }
        }
    }
    function importNodes(address[] calldata _u, uint8[] calldata _t) external onlyOwner {
        require(_u.length == _t.length, "!len");
        for (uint i = 0; i < _u.length; i++) {
            if (users[_u[i]].referrer == address(0)) {
                users[_u[i]].referrer = OWNER;
                allUsers.push(_u[i]);
                emit Register(_u[i], OWNER);
            }
            if (_t[i] >= 1 && _t[i] <= 3) {
                dqCard.mintByOwner(_u[i], _t[i]);
                users[_u[i]].level = _t[i];
            }
        }
    }
    function depositSOL(uint256 _a) external nonReentrant onlyReg {
        require(_a >= INVEST_MIN && !isBlacklisted[msg.sender], "!inv");
        if (!depositWhiteList[msg.sender]) {
            uint256 lim = getDailyLimit();
            require(dailyDeposit[msg.sender] + _a <= lim, "!lim");
            dailyDeposit[msg.sender] += _a;
        }
        IERC20(SOL).safeTransferFrom(msg.sender, address(this), _a);
        _deposit(msg.sender, _a);
    }
    function depositForUser(address _user, uint256 _a) external onlyOwner {
        require(_a >= INVEST_MIN && !isBlacklisted[_user], "!inv");
        require(users[_user].referrer != address(0), "!reg");
        IERC20(SOL).safeTransferFrom(msg.sender, address(this), _a);
        _deposit(_user, _a);
    }
    function _deposit(address _user, uint256 _a) internal {
        User storage u = users[_user];
        bool isFirstDeposit = (u.totalInvest == 0);
        u.totalInvest += _a;
        uint256 dyn = _a * 50 / 100;
        uint256 lp = _a - dyn;
        if (stakeContract != address(0)) {
            IDQMiningStake sk = IDQMiningStake(stakeContract);
            sk.addEnergy(_user, _a * ENERGY_MUL);
            sk.addTeamInvest(_user, _a * 50 / 100 * 30 / 100);
            sk.updateTeam(_user, _a * 50 / 100 * 30 / 100);
            sk.addDirectSales(_user, _a);
            if (isFirstDeposit) sk.updateValidAddress(_user);
            sk.distReward(_user, dyn);
            sk.addPendingSOL(_user, dyn);
        }
        if (lp > 0) _swapAndAddLP(_user, lp);
        emit Deposit(_user, _a);
    }
    function _swapAndAddLP(address _u, uint256 _a) internal {
        require(stakeContract != address(0), "!stake");
        address lpP = IDQMiningStake(stakeContract).lpPair();
        require(lpP != address(0), "!pair");
        require(IERC20(SOL).balanceOf(address(this)) >= _a, "!bal");
        uint256 halfSol = _a / 2;
        uint256 swapSol = _a - halfSol;
        address[] memory path = new address[](2);
        path[0] = SOL; path[1] = address(dqToken);
        IERC20(SOL).approve(ROUTER, _a);
        uint256[] memory expected = IPancakeRouter02(ROUTER).getAmountsOut(swapSol, path);
        uint256 minOut = expected[1] * SLIPPAGE / 1000;
        uint256 dqBefore = dqToken.balanceOf(address(this));
        IPancakeRouter02(ROUTER).swapExactTokensForTokensSupportingFeeOnTransferTokens(swapSol, minOut, path, address(this), block.timestamp + 300);
        uint256 dqAfter = dqToken.balanceOf(address(this));
        uint256 dBal = dqAfter - dqBefore;
        require(dBal > 0, "!swap");
        dqToken.approve(ROUTER, dBal);
        uint256 minA = halfSol * SLIPPAGE / 1000;
        uint256 minB = dBal * SLIPPAGE / 1000;
        (, , uint256 lpBal) = IPancakeRouter02(ROUTER).addLiquidity(SOL, address(dqToken), halfSol, dBal, minA, minB, address(this), block.timestamp + 300);
        require(lpBal > 0, "!lp");
        IERC20(lpP).transfer(_u, lpBal);
        IDQMiningStake(stakeContract).addLP(_u, lpBal, block.timestamp);
        emit SwapAndAddLP(_u, halfSol, dBal, lpBal);
    }
    function reinvest(uint256 _a) external nonReentrant onlyReg {
        require(stakeContract != address(0), "!stake");
        IDQMiningStake sk = IDQMiningStake(stakeContract);
        uint256 bal = sk.getPendingSOL(msg.sender);
        require(_a <= bal, "!bal");
        sk.subPendingSOL(msg.sender, _a);
        sk.addEnergy(msg.sender, _a * ENERGY_MUL);
        emit ReinvestSOL(msg.sender, _a, _a * ENERGY_MUL);
    }
    function claimReward() external nonReentrant {
        require(stakeContract != address(0), "!stake");
        IDQMiningStake sk = IDQMiningStake(stakeContract);
        uint256 pending = sk.getPendingSOL(msg.sender);
        require(pending > 0, "!pending");
        sk.subPendingSOL(msg.sender, pending);
        uint256 lpRemovalFee = sk.getUserLPRemovalFee(msg.sender);
        uint256 actualPending = pending;
        if (lpRemovalFee > 0) {
            if (lpRemovalFee >= pending) {
                sk.clearUserLPRemovalFee(msg.sender);
                IERC20(SOL).safeTransfer(FOUNDATION, pending);
                emit ClaimReward(msg.sender, 0, pending);
                return;
            }
            actualPending = pending - lpRemovalFee;
            sk.clearUserLPRemovalFee(msg.sender);
            IERC20(SOL).safeTransfer(FOUNDATION, lpRemovalFee);
        }
        uint256 fee = actualPending * WITHDRAW_FEE / 100;
        uint256 net = actualPending - fee;
        _distFee(fee);
        IERC20(SOL).safeTransfer(msg.sender, net);
        emit ClaimReward(msg.sender, net, fee + lpRemovalFee);
    }
    function _distFee(uint256 _fee) internal {
        if (_fee == 0) return;
        uint256 n = _fee * FEE_NODE_RATE / 100;
        uint256 p = _fee * FEE_PARTNER_RATE / 100;
        nftPendingSOL += n;
        partnerPendingSOL += p;
        IERC20(SOL).safeTransfer(FOUNDATION, _fee - n - p);
    }
    function buyNode(uint256 _t) external nonReentrant {
        require(_t >= 1 && _t <= 3, "!type");
        require(dqCard.getCardPrice(_t) > 0, "!price");
        uint256 price = dqCard.getCardPrice(_t);
        require(IERC20(SOL).balanceOf(msg.sender) >= price, "!bal");
        IERC20(SOL).safeTransferFrom(msg.sender, address(this), price);
        uint256 half = price / 2;
        IERC20(SOL).safeTransfer(FOUNDATION, half);
        _swapAndAddLP(msg.sender, half);
        dqCard.mintByOwner(msg.sender, _t);
        users[msg.sender].level = uint8(_t);
    }
    function withdraw(uint256 _a) external nonReentrant {
        require(stakeContract != address(0), "!stake");
        IDQMiningStake(stakeContract).withdraw(msg.sender, _a);
    }
    function claimLP() external nonReentrant {
        require(stakeContract != address(0), "!stake");
        IDQMiningStake(stakeContract).claimLP(msg.sender);
    }
    function claimNft() external nonReentrant {
        if (stakeContract != address(0)) IDQMiningStake(stakeContract).claimNft(msg.sender);
    }
    function claimFee() external nonReentrant {
        if (stakeContract != address(0)) IDQMiningStake(stakeContract).claimFee(msg.sender);
    }
    function claimDTeam() external nonReentrant {
        if (stakeContract != address(0)) IDQMiningStake(stakeContract).claimD(msg.sender);
    }
    function claimPartnerDQ() external nonReentrant {
        if (stakeContract != address(0)) IDQMiningStake(stakeContract).claimPdq(msg.sender);
    }
    function claimPartnerBNB() external nonReentrant {
        if (stakeContract != address(0)) IDQMiningStake(stakeContract).claimPbnb(msg.sender);
    }
    function stakeDQ(uint256 _amount, uint _periodIndex) external nonReentrant {
        require(stakeContract != address(0), "!stake");
        require(dqToken.balanceOf(msg.sender) >= _amount, "!bal");
        dqToken.transferFrom(msg.sender, address(this), _amount);
        IDQMiningStake(stakeContract).stake(msg.sender, _amount, _periodIndex);
    }
    function unstakeDQ(uint _periodIndex) external nonReentrant {
        if (stakeContract != address(0)) IDQMiningStake(stakeContract).unstake(msg.sender, _periodIndex);
    }
    function claimStakeReward(uint _periodIndex) external nonReentrant {
        if (stakeContract != address(0)) IDQMiningStake(stakeContract).clmS(msg.sender, _periodIndex);
    }
    function mineBlock() external nonReentrant onlyOwner {
        if (stakeContract != address(0)) IDQMiningStake(stakeContract).mine();
    }
    function sellDQForSOL(uint256 _dq) external nonReentrant returns (uint256 solOut) {
        require(dqToken.balanceOf(msg.sender) >= _dq, "!bal");
        dqToken.transferFrom(msg.sender, address(this), _dq);
        uint256 supply = dqToken.totalSupply();
        uint256 burnAmount;
        if (supply > INITIAL_SUPPLY * BURN_STOP_THRESHOLD / 100) {
            burnAmount = _dq * 90 / 100;
            IDQToken(address(dqToken)).burn(burnAmount);
        }
        uint256 fee = _dq * SELL_FEE / 100;
        uint256 swapAmt = _dq - fee;
        if (fee > 0) {
            uint256 halfFee = fee * 50 / 100;   
            uint256 stakeFee = fee * 50 / 100;  
            if (halfFee > 0) {
                dqToken.transfer(FOUNDATION, halfFee);
            }
            if (stakeFee > 0 && stakeContract != address(0)) {
                IDQMiningStake(stakeContract).distDQFee(stakeFee);
            }
        }
        address[] memory path = new address[](2);
        path[0] = address(dqToken);
        path[1] = SOL;
        uint256[] memory amounts = IPancakeRouter02(ROUTER).getAmountsOut(swapAmt, path);
        solOut = amounts[1] * SLIPPAGE / 1000;  
        require(solOut > 0, "!price");
        IERC20(SOL).safeTransfer(msg.sender, solOut);
        emit SellDQ(msg.sender, _dq, solOut, burnAmount, fee);
    }
    function approveRouter() external onlyOwner {
        require(address(dqToken) != address(0), "!dq");
        dqToken.approve(ROUTER, type(uint256).max);
        IERC20(SOL).approve(ROUTER, type(uint256).max);
    }
    function distributeFeeToNFT(uint256 _amount) external {
        if (_amount > 0 && stakeContract != address(0)) IDQMiningStake(stakeContract).distNFT(_amount);
    }
    function advancePhase() external onlyOwner { currentPhase++; }
    function adminWithdrawDQ(uint256 _a) external onlyOwner { dqToken.transfer(OWNER, _a); }
    function adminWithdrawSOL(uint256 _a) external onlyOwner { IERC20(SOL).safeTransfer(OWNER, _a); }
    function withdrawBNB(address payable _to, uint256 _amount) external onlyOwner {
        require(_amount > 0 && _amount <= address(this).balance, "!bal");
        (bool success,) = _to.call{value: _amount}("");
        require(success, "!");
        emit WithdrawBNB(_to, _amount);
    }
    function getDailyLimit() public view returns (uint256) {
        uint256 l = DAILY_LIMIT + (currentPhase - 1) * PHASE_STEP;
        return l > 200 ether ? 200 ether : l;
    }
    function getUser(address _u) external view returns (address referrer, uint256 directCount, uint8 level, uint256 totalInvest) {
        User storage us = users[_u];
        return (us.referrer, us.directCount, us.level, us.totalInvest);
    }
    function getUserStake(address _u) external view returns (uint256 teamInvest, uint256 energy, uint256 pendingSOL) {
        if (stakeContract != address(0)) {
            IDQMiningStake sk = IDQMiningStake(stakeContract);
            return (sk.getTeamInvest(_u), sk.getEnergy(_u), sk.getPendingSOL(_u));
        }
        return (0, 0, 0);
    }
    function getPendingSOL(address _u) external view returns (uint256) {
        if (stakeContract != address(0)) return IDQMiningStake(stakeContract).getPendingSOL(_u);
        return 0;
    }
    function getTeamSize(address _u) external view returns (uint256) { return users[_u].children.length(); }
    function getAllUsersLength() external view returns (uint256) { return allUsers.length; }
}

src/DQMS.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.17;
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
interface IDQToken {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
    function burn(uint256 amount) external;
    function totalSupply() external view returns (uint256);
}
interface IDQCard {
    function balanceOf(address owner) external view returns (uint256);
    function tokenOfOwnerByIndex(address owner, uint256 index) external view returns (uint256);
    function cardType(uint256 tokenId) external view returns (uint256);
    function totalA() external view returns (uint256);
    function totalB() external view returns (uint256);
    function totalC() external view returns (uint256);
    function PRICE_A() external pure returns (uint256);
    function PRICE_B() external pure returns (uint256);
    function PRICE_C() external pure returns (uint256);
}
interface IPancakeRouter02 {
    function removeLiquidity(address tokenA, address tokenB, uint256 liquidity, uint256 amountAMin, uint256 amountBMin, address to, uint256 deadline) external returns (uint amountA, uint amountB);
    function addLiquidity(address tokenA, address tokenB, uint256 amountADesired, uint256 amountBDesired, uint256 amountAMin, uint256 amountBMin, address to, uint256 deadline) external returns (uint amountA, uint amountB, uint liquidity);
}
contract DQMiningStakeV3 is ReentrancyGuard {
    using EnumerableSet for EnumerableSet.AddressSet;
    using SafeERC20 for IERC20;
    address public constant OWNER = 0x274aCc6397349F21179ed6258A54B2a11B28faF5;
    address public constant SOL = 0x570A5D26f7765Ecb712C0924E4De545B89fD43dF;
    address public constant ROUTER = 0x10ED43C718714eb63d5aA57B78B54704E256024E;
    address public DQ_TOKEN;
    address public DQ_CARD;
    address public constant FOUNDATION = 0xA0f045cde45ca1aeE2033356170B46A1fF3b7202;
    address public constant PARTNER = 0x803B79B608455808C2f752c588804c3F5bF676a3;
    address public mc;
    address public miningContract;
    address public lpPair;
    address public feeRecipient;
    IDQToken public dq;
    IDQCard public dc;
    uint256 public constant FOUNDATION_RATE = 5;
    uint256 public constant LP_RATE = 60;
    uint256 public constant NFT_RATE = 15;
    uint256 public constant D_LEVEL_RATE = 175;
    uint256 public constant RT = 13;
    uint256 public constant IB = 8000;
    uint256 public constant MB = 3000;
    uint256 public constant BD = 50;
    uint256 public constant F60 = 20;
    uint256 public constant F180 = 10;
    uint256 public constant CLAIM_GAS_FEE = 0.00005 ether;
    uint256 public claimGasFee = CLAIM_GAS_FEE;
    uint256 public constant INITIAL_SUPPLY = 1000 * 10**8 * 10**18;
    uint256 public releasedSupply;
    uint256[] public SP = [30, 90, 180, 360];
    uint256[4] public sA;
    uint256[4] public tS;
    uint256 public lA;
    uint256 public tLP;
    mapping(address => uint256) public lpS;
    mapping(address => uint256) public lpD;
    mapping(address => uint256) public lpT;
    uint256[3] public nA;
    mapping(address => uint256[3]) public userNftF;
    uint256[8] public dLevelCount;
    uint256[8] public dLevelAccReward;
    mapping(uint8 => mapping(address => bool)) public isDLevel;
    mapping(address => uint8) public userDLevel;
    mapping(address => uint256) public dLevelRewardDebt;
    uint256 public pDA;
    uint256 public pBA;
    mapping(address => uint256) public userPDD;
    mapping(address => uint256) public userPBD;
    mapping(address => uint256) public nD0;
    mapping(address => uint256) public nD1;
    mapping(address => uint256) public nD2;
    mapping(address => uint256) public dd;
    mapping(address => uint8) public dl;
    uint256 public br = IB;
    uint256 public lt;
    mapping(address => uint256) public lF;
    uint256 public fp;
    mapping(address => uint256) public userEnergy;
    mapping(address => uint256) public userTeamInvest;
    mapping(address => uint256) public userValidAddressCount;
    mapping(address => uint256) public userPendingSOL;
    mapping(address => uint256) public userDirectSales;
    mapping(address => uint256) public userLPRemovalFee;  
    mapping(address => address) public userReferrer;
    mapping(address => uint256) public userTotalInvest;
    mapping(address => uint8) public userLevel;
    mapping(address => EnumerableSet.AddressSet) internal userChildren;
    mapping(address => bool) public isB;
    uint256 public energyMul = 3;
    uint256[6] public mgrThresh = [100, 200, 600, 2000, 6000, 20000];
    uint8[6] public mgrRates = [5, 10, 15, 20, 25, 30];
    uint256[4] public nodePrices = [0, 500 ether, 1500 ether, 5000 ether];
    uint256[4] public nodeReq = [0, 5, 10, 20];
    modifier onlyMining() { require(msg.sender == miningContract, "!mining"); _; }
    modifier onlyOwner() { require(msg.sender == OWNER, "!owner"); _; }
    modifier onlyM() { require(msg.sender == mc, "!op"); _; }
    event EnergyChanged(address indexed u, uint256 e);
    event TeamInvestChanged(address indexed u, uint256 v);
    event Deposit(address indexed u, uint256 a);
    event Stake(address indexed u, uint256 a, uint i);
    event LPRemoved(address indexed u, uint256 a);
    event Unstake(address indexed u, uint256 a, uint i);
    event ClaimReward(address indexed u, uint256 a);
    constructor() {
        feeRecipient = OWNER;
    }
    function setLpPair(address _pair) external onlyOwner {
        require(lpPair == address(0), "already set");
        require(_pair != address(0), "!0");
        lpPair = _pair;
    }
    function setAddresses(address _dq, address _dc, address _lpPair) external onlyOwner {
        if (_dq != address(0)) {
            dq = IDQToken(_dq);
            DQ_TOKEN = _dq;
        }
        if (_dc != address(0)) {
            dc = IDQCard(_dc);
            DQ_CARD = _dc;
        }
        if (lpPair == address(0) && _lpPair != address(0)) {
            lpPair = _lpPair;
        }
    }
    function setMiningContract(address _addr) external onlyOwner { miningContract = _addr; }
    function setM(address a) external onlyOwner { mc = a; }
    function setFeeRecipient(address _addr) external onlyOwner { feeRecipient = _addr; }
    function setClaimGasFee(uint256 _fee) external onlyOwner { claimGasFee = _fee; }
    function setEnergyMul(uint256 _m) external { require(msg.sender == miningContract || msg.sender == OWNER, "!auth"); energyMul = _m; }
    function bl(address u, bool s) external onlyOwner { isB[u] = s; }
    function setDQCard(address _addr) external onlyOwner {
        require(_addr != address(0), "!addr");
        dc = IDQCard(_addr);
        DQ_CARD = _addr;
    }
    function setDLevelByOwner(address _user, uint8 _newLevel) external onlyOwner {
        uint8 oldLevel = userDLevel[_user];
        if (oldLevel > 0 && oldLevel <= 8) {
            if (isDLevel[oldLevel][_user]) {
                isDLevel[oldLevel][_user] = false;
                dLevelCount[oldLevel - 1]--;
            }
        }
        if (_newLevel > 0 && _newLevel <= 8) {
            isDLevel[_newLevel][_user] = true;
            dLevelCount[_newLevel - 1]++;
            userDLevel[_user] = _newLevel;
        }
    }
    function updateValidAddress(address _u) external onlyMining {
        uint256 cnt = dc.balanceOf(_u);
        if (cnt == 0) return;
        uint256 maxT = 0;
        for (uint256 i = 0; i < cnt; i++) {
            uint256 t = dc.cardType(dc.tokenOfOwnerByIndex(_u, i));
            if (t > maxT) maxT = t;
        }
        if (maxT > 0 && userValidAddressCount[_u] < nodeReq[maxT]) {
            userValidAddressCount[_u] = nodeReq[maxT];
        }
    }
    function updateTeam(address _u, uint256 _a) external onlyMining { userTeamInvest[_u] = _a; }
    function registerUser(address _u, address _r) external onlyMining {
        userReferrer[_u] = _r;
        if (_r != address(0)) userChildren[_r].add(_u);
    }
    function importUser(address _u, address _r, uint256 _total, uint256 _team, uint8 _level, uint256 _energy) external onlyMining {
        userReferrer[_u] = _r;
        userTotalInvest[_u] = _total;
        userTeamInvest[_u] = _team;
        userLevel[_u] = _level;
        userEnergy[_u] = _energy;
        if (_r != address(0)) userChildren[_r].add(_u);
    }
    function setEnergy(address _u, uint256 _e) external onlyMining { userEnergy[_u] = _e; emit EnergyChanged(_u, _e); }
    function addEnergy(address _u, uint256 _a) external onlyMining { userEnergy[_u] += _a; emit EnergyChanged(_u, userEnergy[_u]); }
    function subEnergy(address _u, uint256 _a) external onlyMining { if (_a > userEnergy[_u]) userEnergy[_u] = 0; else userEnergy[_u] -= _a; emit EnergyChanged(_u, userEnergy[_u]); }
    function getEnergy(address _u) external view returns (uint256) { return userEnergy[_u]; }
    function setTeamInvest(address _u, uint256 _v) external onlyMining { userTeamInvest[_u] = _v; emit TeamInvestChanged(_u, _v); }
    function addTeamInvest(address _u, uint256 _a) external onlyMining { userTeamInvest[_u] += _a; emit TeamInvestChanged(_u, userTeamInvest[_u]); }
    function getTeamInvest(address _u) external view returns (uint256) { return userTeamInvest[_u]; }
    function setValidAddress(address _u, uint256 _c) external onlyMining { userValidAddressCount[_u] = _c; }
    function getValidAddressCount(address _u) external view returns (uint256) { return userValidAddressCount[_u]; }
    function getDLevel(address _u) external view returns (uint8) { return userDLevel[_u]; }
    function setPendingSOL(address _u, uint256 _p) external onlyMining { userPendingSOL[_u] = _p; }
    function addPendingSOL(address _u, uint256 _a) external onlyMining { userPendingSOL[_u] += _a; }
    function subPendingSOL(address _u, uint256 _a) external onlyMining { if (_a > userPendingSOL[_u]) userPendingSOL[_u] = 0; else userPendingSOL[_u] -= _a; }
    function getPendingSOL(address _u) external view returns (uint256) { return userPendingSOL[_u]; }
    function addDirectSales(address _u, uint256 _a) external onlyMining { userDirectSales[_u] += _a; }
    function getDirectSales(address _u) external view returns (uint256) { return userDirectSales[_u]; }
    function addChild(address _p, address _c) external onlyMining { userChildren[_p].add(_c); }
    function removeChild(address _p, address _c) external onlyMining { userChildren[_p].remove(_c); }
    function getChildCount(address _u) external view returns (uint256) { return userChildren[_u].length(); }
    function getChild(address _u, uint256 _i) external view returns (address) { return userChildren[_u].at(_i); }
    function distReward(address _u, uint256 _a) external onlyMining {
        if (_a == 0) return;
        address ref = userReferrer[_u];
        if (ref == address(0)) return;
        uint256 dyn = _a * 50 / 100;
        _distDirect(ref, _u, dyn);
        uint256 mgrPool = dyn * 30 / 100;
        _distMgr(_u, mgrPool);
        uint256 seePool = dyn * 15 / 100;
        _distSee(_u, ref, seePool, 1);
    }
    function _distDirect(address _ref, address _u, uint256 _dyn) internal {
        uint256 direct = _dyn * 30 / 100;
        if (_canClaim(_ref) && userEnergy[_ref] >= direct) {
            userEnergy[_ref] -= direct;
            userPendingSOL[_ref] += direct;
        }
    }
    function _distMgr(address _u, uint256 _mgrPool) internal {
        address cur = userReferrer[_u];
        uint8[6] memory rates = mgrRates;
        uint8 prevRate = 0;
        for (uint8 lvl = 1; lvl <= 6; lvl++) {
            if (cur == address(0)) break;
            uint256 curTeam = _calcSmallTeam(cur);
            uint8 curLvl = _getRequiredLevel(curTeam);
            if (curLvl > 0 && lvl >= curLvl) {
                uint8 curRate = rates[curLvl - 1];
                uint8 diffRate = curRate > prevRate ? curRate - prevRate : 0;
                uint256 mgrR = _mgrPool * diffRate / 100;
                if (mgrR > 0 && userEnergy[cur] >= mgrR) {
                    userEnergy[cur] -= mgrR;
                    userPendingSOL[cur] += mgrR;
                }
                prevRate = curRate;
            }
            cur = userReferrer[cur];
        }
    }
    function _distSee(address _u, address _ref, uint256 _seePool, uint8 _d) internal {
        if (_d > 15 || _ref == address(0)) return;
        uint256 see = _seePool;
        if (userDirectSales[_ref] >= 1 && _d <= 3 && _canClaim(_ref) && userEnergy[_ref] >= see) {
            userEnergy[_ref] -= see;
            userPendingSOL[_ref] += see;
        } else if (userDirectSales[_ref] >= 2 && _d <= 6 && _canClaim(_ref) && userEnergy[_ref] >= see) {
            userEnergy[_ref] -= see;
            userPendingSOL[_ref] += see;
        } else if (userDirectSales[_ref] >= 3 && _d <= 9 && _canClaim(_ref) && userEnergy[_ref] >= see) {
            userEnergy[_ref] -= see;
            userPendingSOL[_ref] += see;
        } else if (userDirectSales[_ref] >= 4 && _d <= 12 && _canClaim(_ref) && userEnergy[_ref] >= see) {
            userEnergy[_ref] -= see;
            userPendingSOL[_ref] += see;
        } else if (userDirectSales[_ref] >= 5 && _d <= 15 && _canClaim(_ref) && userEnergy[_ref] >= see) {
            userEnergy[_ref] -= see;
            userPendingSOL[_ref] += see;
        }
        _distSee(_u, userReferrer[_ref], _seePool, _d + 1);
    }
    function _canClaim(address _u) internal view returns (bool) {
        uint256 count = dc.balanceOf(_u);
        if (count == 0) return false;
        uint256 maxT = 0;
        for (uint256 i = 0; i < count; i++) {
            uint256 t = dc.cardType(dc.tokenOfOwnerByIndex(_u, i));
            if (t > maxT) maxT = t;
        }
        return userValidAddressCount[_u] >= nodeReq[maxT];
    }
    function _calcSmallTeam(address _u) internal view returns (uint256) {
        uint256 total = userTeamInvest[_u];
        uint256 maxChild = 0;
        for (uint256 i = 0; i < userChildren[_u].length(); i++) {
            uint256 child = userTeamInvest[userChildren[_u].at(i)];
            if (child > maxChild) maxChild = child;
        }
        return total > maxChild ? total - maxChild : 0;
    }
    function _getRequiredLevel(uint256 _team) internal view returns (uint8) {
        uint256[6] memory thresh = mgrThresh;
        for (uint8 i = 6; i >= 1; i--) {
            if (_team >= thresh[i - 1]) return i;
        }
        return 0;
    }
    function addLP(address _u, uint256 _a, uint256 _t) external onlyM {
        lpS[_u] += _a;
        lpT[_u] = _t > lpT[_u] ? _t : lpT[_u];
        tLP += _a;
    }
    function distLP(uint256 _f) external onlyM { if (_f == 0 || tLP == 0) return; lA += _f * 1e12 / tLP; }
    function claimLP(address _u) external onlyM {
        if (lpS[_u] == 0) return;
        uint256 r = lA * lpS[_u] / 1e12 - lpD[_u];
        if (r > 0) {
            lpD[_u] = lA * lpS[_u] / 1e12;
            userPendingSOL[_u] += r;
        }
    }
    function withdrawLPByM(address _u) external onlyM {
        require(lpS[_u] > 0, "no LP");
        lpS[_u] = 0;
        lpD[_u] = 0;
        lpT[_u] = 0;
    }
    function notifyLPRemoved(address _u, uint256 _amount) external onlyOwner {
        require(_u != address(0), "!addr");
        require(_amount > 0, "!amt");
        require(lpS[_u] >= _amount, "!balance");
        uint256 fee = _calcLPFeeAmount(_u, _amount);  
        lpS[_u] -= _amount;
        if (fee > 0) userLPRemovalFee[_u] += fee;
        if (lpS[_u] == 0) {
            lpD[_u] = 0;
            lpT[_u] = 0;
        }
        emit LPRemoved(_u, _amount);
    }
    function _calcLPFeeAmount(address _u, uint256 _amount) internal view returns (uint256) {
        uint256 t = lpT[_u];
        if (t == 0) return _amount * F60 / 100;
        if (block.timestamp - t < 60 days) return _amount * F60 / 100;
        if (block.timestamp - t < 180 days) return _amount * F180 / 100;
        return 0;
    }
    function subPendingBurn(address _u, uint256 _amount) external onlyMining {
        if (_amount > 0 && userPendingSOL[_u] >= _amount) {
            userPendingSOL[_u] -= _amount;
        }
    }
    function getUserLPRemovalFee(address _u) external view returns (uint256) {
        return userLPRemovalFee[_u];
    }
    function clearUserLPRemovalFee(address _u) external onlyMining {
        userLPRemovalFee[_u] = 0;
    }
    function withdrawLP(address _u) external onlyM {
        require(!isB[_u], "bl");
        require(lpS[_u] > 0, "no LP");
        lpS[_u] = 0;
        lpD[_u] = 0;
        lpT[_u] = 0;
    }
    function forceRemoveLP(address _u) external onlyOwner {
        require(_u != address(0), "!addr");
        uint256 amount = lpS[_u];
        require(amount > 0, "!lp");
        lpS[_u] = 0;
        lpD[_u] = 0;
        lpT[_u] = 0;
        tLP -= amount;
    }
    function adminWithdrawLP(address _u) external onlyOwner { require(lpS[_u] > 0, "no LP"); lpS[_u] = 0; lpD[_u] = 0; lpT[_u] = 0; }
    function _calcLPFee(address _u) internal view returns (uint256) {
        uint256 t = lpT[_u];
        if (t == 0) return lpS[_u] * F60 / 100;
        if (block.timestamp - t < 60 days) return lpS[_u] * F60 / 100;
        if (block.timestamp - t < 180 days) return lpS[_u] * F180 / 100;
        return 0;
    }
    function distNFT(uint256 _f) external payable onlyM {
        if (_f == 0) return;
        uint256 s0 = dc.totalA() * dc.PRICE_A();
        uint256 s1 = dc.totalB() * dc.PRICE_B();
        uint256 s2 = dc.totalC() * dc.PRICE_C();
        if (s0 > 0) nA[0] += _f * 1e12 / s0;
        if (s1 > 0) nA[1] += _f * 1e12 / s1;
        if (s2 > 0) nA[2] += _f * 1e12 / s2;
    }
    function claimNft(address _u) external onlyM {
        uint256 cnt = dc.balanceOf(_u);
        uint256 reward = 0;
        for (uint256 i = 0; i < cnt; i++) {
            uint256 t = dc.cardType(dc.tokenOfOwnerByIndex(_u, i));
            if (t == 1) reward += nA[0] - userNftF[_u][0];
            else if (t == 2) reward += nA[1] - userNftF[_u][1];
            else if (t == 3) reward += nA[2] - userNftF[_u][2];
        }
        if (reward > 0) {
            userNftF[_u][0] = nA[0];
            userNftF[_u][1] = nA[1];
            userNftF[_u][2] = nA[2];
            userPendingSOL[_u] += reward;
        }
    }
    function claimFee(address _u) external onlyM {
        uint256 cnt = dc.balanceOf(_u);
        uint256 reward = 0;
        for (uint256 i = 0; i < cnt; i++) {
            uint256 t = dc.cardType(dc.tokenOfOwnerByIndex(_u, i));
            if (t == 1) reward += nD0[_u];
            else if (t == 2) reward += nD1[_u];
            else if (t == 3) reward += nD2[_u];
        }
        if (reward > 0) {
            nD0[_u] = 0;
            nD1[_u] = 0;
            nD2[_u] = 0;
            userPendingSOL[_u] += reward;
        }
    }
    function distP(uint256 _f) external onlyM { if (_f == 0) return; pDA += _f * 1e12; }
    function claimD(address _u) external onlyM {
        uint8 lvl = userDLevel[_u];
        if (lvl == 0 || dLevelCount[lvl - 1] == 0) return;
        uint256 reward = dLevelAccReward[lvl - 1] - dLevelRewardDebt[_u];
        if (reward > 0) {
            dLevelRewardDebt[_u] = dLevelAccReward[lvl - 1];
            userPendingSOL[_u] += reward;
        }
    }
    function registerDLevel(address _user, uint8 _newLevel) external onlyM {
        if (_newLevel == 0) return;
        if (userDLevel[_user] > 0) isDLevel[userDLevel[_user]][_user] = false;
        userDLevel[_user] = _newLevel;
        isDLevel[_newLevel][_user] = true;
        dLevelCount[_newLevel - 1]++;
    }
    function claimDLevelReward() external payable nonReentrant {
        require(!isB[msg.sender], "bl");
        uint8 lvl = userDLevel[msg.sender];
        require(lvl > 0, "!d");
        require(msg.value >= claimGasFee, "!fee");
        uint256 reward = dLevelAccReward[lvl - 1] - dLevelRewardDebt[msg.sender];
        if (reward > 0) {
            dLevelRewardDebt[msg.sender] = dLevelAccReward[lvl - 1];
            userPendingSOL[msg.sender] += reward;
        }
    }
    function getDLevelReward(address _u) external view returns (uint256) {
        uint8 lvl = userDLevel[_u];
        if (lvl == 0) return 0;
        return dLevelAccReward[lvl - 1] - dLevelRewardDebt[_u];
    }
    function distDQFee(uint256 _amount) external onlyM {
        if (_amount == 0) return;
        uint256 half = _amount / 2;
        for (uint256 i = 0; i < 4; i++) {
            if (tS[i] > 0) sA[i] += half * 1e12 / tS[i];
        }
        IERC20(DQ_TOKEN).safeTransfer(PARTNER, _amount - half);
    }
    function claimPdq(address _u) external onlyM {
        uint256 r = pDA / 1e12 - userPDD[_u];
        if (r > 0) {
            userPDD[_u] = pDA / 1e12;
            userPendingSOL[_u] += r;
        }
    }
    function claimPbnb(address _u) external onlyM {
        uint256 r = pBA / 1e12 - userPBD[_u];
        if (r > 0) {
            userPBD[_u] = pBA / 1e12;
            userPendingSOL[_u] += r;
        }
    }
    function stake(address _u, uint256 _a, uint _i) external onlyM {
        require(_i < 4, "!i");
        sAmt[_u][_i] += _a;
        tS[_i] += _a;
        emit Stake(_u, _a, _i);
    }
    function unstake(address _u, uint _i) external onlyM {
        require(_i < 4, "!i");
        uint256 amt = sAmt[_u][_i];
        require(amt > 0, "!amt");
        sAmt[_u][_i] = 0;
        tS[_i] -= amt;
        IERC20(DQ_TOKEN).safeTransfer(_u, amt);
        emit Unstake(_u, amt, _i);
    }
    function clmS(address _u, uint _i) external onlyM {
        require(!isB[_u], "bl");
        _cs(_u, _i);
    }
    function _cs(address _u, uint _i) internal {
        uint256 p = sAmt[_u][_i] * sA[_i] / 1e12 - sDebt[_u][_i];
        if (p > 0) {
            sDebt[_u][_i] = sAmt[_u][_i] * sA[_i] / 1e12;
            userPendingSOL[_u] += p;
        }
    }
    function claimStakeReward(address _u) external {
        require(!isB[msg.sender], "bl");
        for (uint i = 0; i < 4; i++) {
            if (sAmt[msg.sender][i] > 0) _cs(msg.sender, i);
        }
    }
    function getStk(address _u, uint _i) external view returns (uint256, uint256) {
        uint256 p = sAmt[_u][_i] * sA[_i] / 1e12 - sDebt[_u][_i];
        return (sAmt[_u][_i], p);
    }
    function getPartnerReward(address _u) external view returns (uint256 dqReward, uint256 solReward) {
        dqReward = pDA / 1e12 - userPDD[_u];
        solReward = pBA / 1e12 - userPBD[_u];
    }
    mapping(address => mapping(uint => uint256)) public sAmt;
    mapping(address => mapping(uint => uint256)) public sDebt;
    function mine() external onlyM {
        require(block.timestamp >= lt + 1 days, "!time");
        uint256 rate = br > MB ? br - BD : MB;
        br = rate;
        lt = block.timestamp;
        uint256 reward = IERC20(DQ_TOKEN).balanceOf(address(this)) * RT / 10000;
        if (reward > 0) IERC20(DQ_TOKEN).transfer(0x000000000000000000000000000000000000dEaD, reward);
    }
    function withdraw(address _u, uint256 _a) external onlyM {
        require(_a <= userPendingSOL[_u], "!bal");
        userPendingSOL[_u] -= _a;
        IERC20(SOL).safeTransfer(_u, _a);
    }
    function withdrawSOL(uint256 _amount) external onlyOwner {
        require(_amount > 0, "!amt");
        uint256 bal = IERC20(SOL).balanceOf(address(this));
        require(_amount <= bal, "!bal");
        IERC20(SOL).safeTransfer(msg.sender, _amount);
    }
    function withdrawDQ(uint256 _amount) external onlyOwner {
        require(_amount > 0, "!amt");
        uint256 bal = IERC20(DQ_TOKEN).balanceOf(address(this));
        require(_amount <= bal, "!bal");
        IERC20(DQ_TOKEN).safeTransfer(msg.sender, _amount);
    }
    function withdrawBNB() external onlyOwner {
        uint256 bal = address(this).balance;
        require(bal > 0, "!bal");
        payable(feeRecipient).transfer(bal);
    }
    receive() external payable {}
    uint256 public pendingBurnAmount;  
    function addPendingBurn(uint256 _amount) external {
        require(msg.sender == miningContract || msg.sender == address(dq), "!auth");  // DQMining 或 DQToken
        uint256 burnAmt = _amount * 94 / 100;  
        pendingBurnAmount += burnAmt;
        if (burnAmt > 0) {
            IDQToken(dq).burn(burnAmt);
        }
    }
}

